      <text x="76" y="106" fill="#e4e4e7" font-size="12" text-anchor="middle">Hornby, auditoría IA</text>
      <text x="76" y="126" fill="#a1a1aa" font-size="12" text-anchor="middle">Fallo de 4 años</text>

      <rect x="148" y="58" width="128" height="96" rx="10" fill="#1c1a10" stroke="#f7931a" stroke-width="1.6"/>
      <text x="212" y="84" fill="#f7931a" font-size="13" font-weight="700" text-anchor="middle">2-3/6: Parche</text>
      <text x="212" y="106" fill="#e4e4e7" font-size="12" text-anchor="middle">Soft fork</text>
      <text x="212" y="126" fill="#e4e4e7" font-size="12" text-anchor="middle">Hard fork NU6.2</text>

      <rect x="284" y="58" width="128" height="96" rx="10" fill="#241016" stroke="#ef4444" stroke-width="1.6"/>
